class Graph {
    private final Map<String, Map<String, Integer>> graph = new HashMap<>();

    public void addEdge(String from, String to, int trafficDensity) {
        graph.computeIfAbsent(from, k -> new HashMap<>()).put(to, trafficDensity);
        graph.computeIfAbsent(to, k -> new HashMap<>());
    }

    public Map<String, Map<String, Integer>> getGraph() {
        return graph;
    }
}

public class TrafficOptimizer {

    public static List<String> trafficOptimizer(Graph cityGraph) {
        // Dijkstra's Algorithm to find the shortest path based on traffic density
        Map<String, Integer> distances = new HashMap<>();
        Map<String, String> previousNodes = new HashMap<>();
        PriorityQueue<String> nodes = new PriorityQueue<>(Comparator.comparingInt(distances::get));

        for (String node : cityGraph.getGraph().keySet()) {
            distances.put(node, Integer.MAX_VALUE);
            nodes.add(node);
        }

        distances.put("StartIntersection", 0); // Assume "StartIntersection" is starting node

        while (!nodes.isEmpty()) {
            String closestNode = nodes.poll();

            if (distances.get(closestNode) == Integer.MAX_VALUE)
                break;

            for (Map.Entry<String, Integer> neighbor : cityGraph.getGraph().get(closestNode).entrySet()) {
                int newDist = distances.get(closestNode) + neighbor.getValue();
                if (newDist < distances.get(neighbor.getKey())) {
                    distances.put(neighbor.getKey(), newDist);
                    previousNodes.put(neighbor.getKey(), closestNode);
                    nodes.add(neighbor.getKey());
                }
            }
        }

        return reconstructPath(previousNodes, "StartIntersection", "DestinationIntersection"); // Assume a destination
    }

    private static List<String> reconstructPath(Map<String, String> previousNodes, String start, String end) {
        List<String> path = new ArrayList<>();
        for (String at = end; at != null; at = previousNodes.get(at)) {
            path.add(at);
        }
        Collections.reverse(path);
        return path.isEmpty() || !path.get(0).equals(start) ? Collections.emptyList() : path;
    }

    public static void main(String[] args) {
        Graph cityGraph = new Graph();
        cityGraph.addEdge("StartIntersection", "A", 3);
        cityGraph.addEdge("A", "B", 3);
        cityGraph.addEdge("B", "DestinationIntersection", 4);
        cityGraph.addEdge("StartIntersection", "C", 2);
        cityGraph.addEdge("C", "DestinationIntersection", 3);

        List<String> optimizedPath = trafficOptimizer(cityGraph);
        System.out.println("Optimized Path: " + optimizedPath);
    }
}
