public class NetworkAnalyzer {

    public List<Integer> analyzeNetworkConnectivity(Map<Integer, List<Integer>> graph) {
        List<Integer> criticalNodes = new ArrayList<>();
        Set<Integer> visited = new HashSet<>();

        for (Integer node : graph.keySet()) {
            visited.clear();
            Set<Integer> remainingNodes = new HashSet<>(graph.keySet());
            remainingNodes.remove(node);
            dfs(graph, remainingNodes.iterator().next(), visited, remainingNodes);

            if (visited.size() < remainingNodes.size()) {
                criticalNodes.add(node);
            }
        }

        return criticalNodes;
    }

    private void dfs(Map<Integer, List<Integer>> graph, Integer current, Set<Integer> visited, Set<Integer> remainingNodes) {
        visited.add(current);

        for (Integer neighbor : graph.getOrDefault(current, new ArrayList<>())) {
            if (remainingNodes.contains(neighbor) && !visited.contains(neighbor)) {
                dfs(graph, neighbor, visited, remainingNodes);
            }
        }
    }
}
