struct PermissionNode {
    std::string name;
    std::vector<PermissionNode*> children;
};

void addPermission(PermissionNode* root, const std::string& parent, const std::string& permission) {
    if (root->name == parent) {
        root->children.push_back(new PermissionNode{permission, {}});
        return;
    }
    for (auto* child : root->children) {
        addPermission(child, parent, permission);
    }
}

void updatePermission(PermissionNode* root, const std::string& oldName, const std::string& newName) {
    if (root->name == oldName) {
        root->name = newName;
        return;
    }
    for (auto* child : root->children) {
        updatePermission(child, oldName, newName);
    }
}

void removePermission(PermissionNode* &root, const std::string& permission) {
    for (auto it = root->children.begin(); it != root->children.end(); ++it) {
        if ((*it)->name == permission) {
            delete *it;
            root->children.erase(it);
            return;
        }
        removePermission(*it, permission);
    }
}

PermissionNode* managePermissions(PermissionNode* permissionTree, const std::string& operation, const std::string& target, const std::string& detail = "") {
    if (operation == "add") {
        addPermission(permissionTree, target, detail);
    } else if (operation == "update") {
        updatePermission(permissionTree, target, detail);
    } else if (operation == "remove") {
        removePermission(permissionTree, target);
    }
    return permissionTree;
}

void printTree(PermissionNode* root, int depth = 0) {
    for (int i = 0; i < depth; ++i) std::cout << "  ";
    std::cout << root->name << std::endl;
    for (auto* child : root->children) {
        printTree(child, depth + 1);
    }
}

