use std::collections::{HashMap, VecDeque};

#[derive(Debug, Clone)]
struct NetworkNode {
    id: String,
    data: HashMap<String, String>,
    children: HashMap<String, NetworkNode>,
}

impl NetworkNode {
    fn new(id: &str, data: HashMap<String, String>) -> Self {
        Self {
            id: id.to_string(),
            data,
            children: HashMap::new(),
        }
    }

    fn add_child(&mut self, child: NetworkNode) {
        self.children.insert(child.id.clone(), child);
    }

    fn remove_child(&mut self, id: &str) {
        self.children.remove(id);
    }

    fn update_data(&mut self, new_data: HashMap<String, String>) {
        self.data = new_data;
    }

    fn get_node(&self, id: &str) -> Option<&NetworkNode> {
        if self.id == id {
            return Some(self);
        }
        let mut queue = VecDeque::new();
        queue.push_back(self);
        while let Some(node) = queue.pop_front() {
            for child in node.children.values() {
                if child.id == id {
                    return Some(child);
                }
                queue.push_back(child);
            }
        }
        None
    }
}

fn manageNetworkConfig(
    root: &mut NetworkNode,
    action: &str,
    target_node_id: Option<&str>,
    details: Option<HashMap<String, String>>,
) -> Option<HashMap<String, String>> {
    match action {
        "add" => {
            if let (Some(target_node_id), Some(details)) = (target_node_id, details) {
                let new_node = NetworkNode::new(target_node_id, details);
                root.add_child(new_node);
            }
            None
        }
        "update" => {
            if let (Some(target_node_id), Some(details)) = (target_node_id, details) {
                if let Some(node) = root.get_node(target_node_id) {
                    let mut mutable_node = unsafe { &mut *(node as *const _ as *mut NetworkNode) };
                    mutable_node.update_data(details);
                }
            }
            None
        }
        "remove" => {
            if let Some(target_node_id) = target_node_id {
                root.remove_child(target_node_id);
            }
            None
        }
        "retrieve" => {
            if let Some(target_node_id) = target_node_id {
                if let Some(node) = root.get_node(target_node_id) {
                    return Some(node.data.clone());
                }
            }
            None
        }
        _ => None,
    }
}

