    public static void graphTraversalManager(String inputJson) {
        JSONObject input = new JSONObject(inputJson);
        String algorithm = input.getString("algorithm");
        String startNode = input.getString("startNode");
        String graphType = input.getString("graphType");
        JSONObject adjacencyListJson = input.getJSONObject("adjacencyList");

        Map<String, List<String>> adjacencyList = new HashMap<>();
        for (String key : adjacencyListJson.keySet()) {
            List<String> neighbors = new ArrayList<>();
            for (Object neighbor : adjacencyListJson.getJSONArray(key)) {
                neighbors.add(neighbor.toString());
            }
            adjacencyList.put(key, neighbors);
        }

        if (algorithm.equalsIgnoreCase("BFS")) {
            bfsTraversal(startNode, adjacencyList);
        } else if (algorithm.equalsIgnoreCase("DFS")) {
            dfsTraversal(startNode, adjacencyList);
        } else {
            System.out.println("Invalid traversal algorithm.");
        }
    }

    private static void bfsTraversal(String startNode, Map<String, List<String>> adjacencyList) {
        Queue<String> queue = new LinkedList<>();
        Set<String> visited = new HashSet<>();

        queue.add(startNode);
        visited.add(startNode);

        while (!queue.isEmpty()) {
            String node = queue.poll();
            System.out.print(node + " ");

            for (String neighbor : adjacencyList.getOrDefault(node, new ArrayList<>())) {
                if (!visited.contains(neighbor)) {
                    queue.add(neighbor);
                    visited.add(neighbor);
                }
            }
        }
    }

    private static void dfsTraversal(String startNode, Map<String, List<String>> adjacencyList) {
        Stack<String> stack = new Stack<>();
        Set<String> visited = new HashSet<>();

        stack.push(startNode);

        while (!stack.isEmpty()) {
            String node = stack.pop();

            if (!visited.contains(node)) {
                System.out.print(node + " ");
                visited.add(node);
            }

            for (String neighbor : adjacencyList.getOrDefault(node, new ArrayList<>())) {
                if (!visited.contains(neighbor)) {
                    stack.push(neighbor);
                }
            }
        }
    }

    public static void main(String[] args) {
        // Example Input JSON
        String inputJson = """
        {
            "algorithm": "BFS",
            "startNode": "A",
            "graphType": "directed",
            "adjacencyList": {
                "A": ["B", "C"],
                "B": ["D", "E"],
                "C": ["F"],
                "D": [],
                "E": ["F"],
                "F": []
            }
        }
        """;

        graphTraversalManager(inputJson);
    }
}
