    public String fsSimulator(String jsonInput) {
        try {
            Map<String, Map<String, Object>> actions = new Gson().fromJson(jsonInput, Map.class);
            for (String action : actions.keySet()) {
                Map<String, Object> details = actions.get(action);
                switch (action) {
