                        removeFolder((String) details.get("name"));
                        break;
                    case "fetchPath":
                        String path = fetchPath((String) details.get("name"));
                        return path != null ? path : "Folder not found";
                }
            }
        } catch (Exception e) {
            return "Error processing JSON input";
        }
        return "Operation completed successfully";
    }

    private void addFolder(String parent, String name) {
        folderMap.put(name, parent);
    }

    private void moveFolder(String name, String newParent) {
        if (folderMap.containsKey(name)) {
            folderMap.put(name, newParent);
        }
    }

    private void removeFolder(String name) {
        folderMap.remove(name);
    }

    private String fetchPath(String name) {
        if (folderMap.containsKey(name)) {
            List<String> pathParts = new ArrayList<>();
            String current = name;
            while (current != null) {
                pathParts.add(current);
                current = folderMap.get(current);
            }
            Collections.reverse(pathParts);
            return String.join("/", pathParts);
        }
        return null;
    }
}
