using namespace std;

vector<int> findShortestPath(const unordered_map<int, vector<pair<int, int>>>& graph, int start, int end) {
    unordered_map<int, int> distances;
    unordered_map<int, int> previous;
    for (const auto& node : graph) {
        distances[node.first] = INT_MAX;
    }
    distances[start] = 0;

    auto compare = [](pair<int, int> left, pair<int, int> right) {
        return left.second > right.second;
    };
    priority_queue<pair<int, int>, vector<pair<int, int>>, decltype(compare)> pq(compare);

    pq.push({start, 0});

    while (!pq.empty()) {
        int currentNode = pq.top().first;
        int currentDistance = pq.top().second;
        pq.pop();

        if (currentNode == end) break;

        if (currentDistance > distances[currentNode]) continue;

        for (const auto& neighbor : graph.at(currentNode)) {
            int adjacent = neighbor.first;
            int weight = neighbor.second;

            int distanceViaCurrent = currentDistance + weight;
            if (distanceViaCurrent < distances[adjacent]) {
                distances[adjacent] = distanceViaCurrent;
                previous[adjacent] = currentNode;
                pq.push({adjacent, distanceViaCurrent});
            }
        }
    }

    vector<int> path;
    for (int at = end; previous.find(at) != previous.end(); at = previous[at]) {
        path.push_back(at);
    }
    if (!path.empty() && path.back() != start) {
        path.clear();
    } else {
        path.push_back(start);
        reverse(path.begin(), path.end());
    }

    return path;
}
