public class MatrixTransformer {

    public static int[][] transformMatrix(int[][] matrix, String operation) {
        int[][] result;
        switch (operation) {
            case "rotate_left":
                result = rotateLeft(matrix);
                break;
            case "rotate_right":
                result = rotateRight(matrix);
                break;
            case "flip_vertical":
                result = flipVertical(matrix);
                break;
            case "flip_horizontal":
                result = flipHorizontal(matrix);
                break;
            default:
                throw new IllegalArgumentException("Invalid operation mode");
        }
        return result;
    }

    private static int[][] rotateLeft(int[][] matrix) {
        int rows = matrix.length;
        int cols = matrix[0].length;
        int[][] rotated = new int[cols][rows];
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                rotated[cols - j - 1][i] = matrix[i][j];
            }
        }
        return rotated;
    }

    private static int[][] rotateRight(int[][] matrix) {
        int rows = matrix.length;
        int cols = matrix[0].length;
        int[][] rotated = new int[cols][rows];
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                rotated[j][rows - i - 1] = matrix[i][j];
            }
        }
        return rotated;
    }

    private static int[][] flipVertical(int[][] matrix) {
        int rows = matrix.length;
        int cols = matrix[0].length;
        int[][] flipped = new int[rows][cols];
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                flipped[rows - i - 1][j] = matrix[i][j];
            }
        }
        return flipped;
    }

    private static int[][] flipHorizontal(int[][] matrix) {
        int rows = matrix.length;
        int cols = matrix[0].length;
        int[][] flipped = new int[rows][cols];
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                flipped[i][cols - j - 1] = matrix[i][j];
            }
        }
        return flipped;
    }
